// ─────────────────────────────────────────────────────────────
// Build Active Planting SELECT
//
// Purpose:
//   Retrieve occupied planting assignments from the active outside
//   hydroponics season for the Home Assistant harvest selector.
//
// Ownership:
//   Node-RED reads v_hydro_current_planting.
//   MariaDB remains authoritative for planting relationships.
//
// GAL 2026-07-22
// - Initial production harvest selector query.
// ─────────────────────────────────────────────────────────────

msg.topic = `
SELECT
    planting_id,
    position_code,
    channel,
    crop_name,
    variety_name,
    plant_count
FROM v_hydro_current_planting
WHERE system_key = 'outside'
  AND planting_status = 'planted'
ORDER BY
    CASE channel
        WHEN 'East' THEN 1
        WHEN 'West' THEN 2
        ELSE 3
    END,
    position_number;
`;

return msg;

// ─────────────────────────────────────────────────────────────
// Build Harvest Selector Options
//
// Purpose:
//   Convert active planting rows into operator-facing Home Assistant
//   input_select options and retain the matching planting_id map.
//
// Display example:
//   E1 — Sweet Bell Pepper
//
// Stored flow context:
//   harvestPlantingMap
//     Maps the displayed selector option to its planting_id.
//
// GAL 2026-07-22
// - Initial production option formatter and planting ID map.
// ─────────────────────────────────────────────────────────────

const rows = Array.isArray(msg.payload) ? msg.payload : [];

const options = ["(select planting)"];
const plantingMap = {};

for (const row of rows) {
    const position = String(row.position_code || "").trim();
    const variety = String(row.variety_name || "").trim();
    const crop = String(row.crop_name || "").trim();

    if (!position || !variety || !crop) {
        continue;
    }

    const option = `${position} — ${variety} ${crop}`;

    options.push(option);
    plantingMap[option] = Number(row.planting_id);
}

// Retain the authoritative option-to-planting relationship for the
// later harvest submission flow.
flow.set("harvestPlantingMap", plantingMap);

msg.options = options;
msg.plantingMap = plantingMap;
msg.payload = {
    options: options
};

return msg;
